import{_ as a,o,c as i,a2 as t}from"./chunks/framework.DtwafDNl.js";const m=JSON.parse('{"title":"Audio Management","description":"","frontmatter":{},"headers":[],"relativePath":"features/audio.md","filePath":"features/audio.md"}'),r={name:"features/audio.md"};function l(n,e,s,d,p,u){return o(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="audio-management" tabindex="-1">Audio Management <a class="header-anchor" href="#audio-management" aria-label="Permalink to &quot;Audio Management&quot;">​</a></h1><p>Audio Management is the library for prompts used across call flows. Teams can upload common audio formats and reuse those files anywhere a flow needs to play a greeting, menu prompt, timeout message, or confirmation message.</p><p>Uploaded files are converted automatically for telephony playback and browser preview, so you do not need to prepare multiple versions by hand. Callytics also supports offline text-to-speech generation with Piper, including multiple voices and speed control.</p><p>Before saving or reusing audio, you can preview it in the browser. Search and delete tools keep the library manageable as the number of prompts grows.</p><h2 id="capabilities" tabindex="-1">Capabilities <a class="header-anchor" href="#capabilities" aria-label="Permalink to &quot;Capabilities&quot;">​</a></h2><ul><li>Upload audio in mp3, wav, m4a, and ogg formats</li><li>Automatic conversion for telephony playback</li><li>Automatic conversion for browser preview</li><li>Offline Piper text-to-speech generation</li><li>Multiple TTS voice options</li><li>TTS speed control</li><li>Preview before saving</li><li>Searchable audio library</li><li>Reuse audio across any flow node</li><li>Delete management for unused audio</li></ul>',6)])])}const f=a(r,[["render",l]]);export{m as __pageData,f as default};
